import { GoogleGenAI, Type } from "@google/genai";
import { Task, MorningBriefing } from "../types";

/**
 * Generates a personalized morning briefing based on today's pending tasks.
 * Uses Gemini 3 Flash for efficient, high-quality reasoning.
 */
export async function generateMorningBriefing(tasks: Task[]): Promise<MorningBriefing> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const taskListText = tasks.length > 0 
    ? tasks.map(t => `- ${t.title} (Priority: ${t.priority})`).join('\n')
    : "No major tasks scheduled for today.";

  const prompt = `
    You are a wise, calming, and highly productive life coach. 
    It is early morning. Help the user start their day with focus and positivity.

    Current Tasks for Today:
    ${taskListText}

    Please generate:
    1. A beautiful, inspiring, and unique morning quote.
    2. A short personalized "Zen Message" (2-3 sentences) summarizing the day's vibe and offering encouragement based on their tasks.
    3. A few "Strategic Action Items" (2-3) which might be creative ways to approach their list or self-care tips.

    Return the response strictly as JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            quote: { type: Type.STRING },
            author: { type: Type.STRING },
            message: { type: Type.STRING },
            actionItems: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["quote", "author", "message", "actionItems"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return {
      quote: data.quote || "The sun rises every day, offering a new chance to begin.",
      author: data.author || "Traditional Zen Saying",
      message: data.message || "Take a deep breath. Today is a clean slate for your ambitions.",
      actionItems: data.actionItems || ["Start with your most challenging task first.", "Take five minutes to meditate before beginning work."],
      generatedAt: Date.now()
    };
  } catch (error) {
    console.error("Error generating Gemini briefing:", error);
    // Fallback data
    return {
      quote: "Success is not final, failure is not fatal: it is the courage to continue that counts.",
      author: "Winston Churchill",
      message: "An error occurred generating your personalized briefing, but your path remains clear.",
      actionItems: ["Review your list manually.", "Take a deep breath and start with step one."],
      generatedAt: Date.now()
    };
  }
}

import { Task, UserSettings } from "../types";

/**
 * Service to handle API calls to the FastAPI backend.
 * This integrates the frontend with your Supabase-backed Python server.
 */
export const apiService = {
  async getTasks(baseUrl: string): Promise<Task[]> {
    const response = await fetch(`${baseUrl}/tasks`);
    if (!response.ok) throw new Error('Failed to fetch tasks');
    return response.json();
  },

  async createTask(baseUrl: string, task: Omit<Task, 'id' | 'createdAt' | 'completed'>): Promise<Task> {
    const response = await fetch(`${baseUrl}/tasks`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(task),
    });
    if (!response.ok) throw new Error('Failed to create task');
    return response.json();
  },

  async toggleTask(baseUrl: string, taskId: string): Promise<Task> {
    const response = await fetch(`${baseUrl}/tasks/${taskId}/toggle`, {
      method: 'PATCH',
    });
    if (!response.ok) throw new Error('Failed to update task');
    return response.json();
  },

  async deleteTask(baseUrl: string, taskId: string): Promise<void> {
    const response = await fetch(`${baseUrl}/tasks/${taskId}`, {
      method: 'DELETE',
    });
    if (!response.ok) throw new Error('Failed to delete task');
  }
};

export enum TaskPriority {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH'
}

export interface Task {
  id: string;
  title: string;
  description: string;
  date: string; // ISO format
  completed: boolean;
  priority: TaskPriority;
  createdAt: number;
}

export interface MorningBriefing {
  quote: string;
  author: string;
  message: string;
  actionItems: string[];
  generatedAt: number;
}

export interface UserSettings {
  email: string;
  preferredMorningTime: string; // HH:mm
  backendUrl?: string;
  brevoApiKey?: string;
  supabaseUrl?: string;
}

import React, { useState, useEffect } from 'react';
import { 
  Calendar as CalendarIcon, 
  CheckCircle2, 
  Clock, 
  LayoutDashboard, 
  Plus, 
  Settings as SettingsIcon,
  Sun,
  Trash2,
  Mail,
  Sparkles,
  ChevronLeft,
  ChevronRight,
  RefreshCw,
  Database
} from 'lucide-react';
import { Task, TaskPriority, MorningBriefing, UserSettings } from './types';
import { generateMorningBriefing } from './services/geminiService';
import { apiService } from './services/apiService';

const STORAGE_KEY = 'morningzen_tasks';
const SETTINGS_KEY = 'morningzen_settings';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'calendar' | 'settings'>('dashboard');
  const [tasks, setTasks] = useState<Task[]>([]);
  const [settings, setSettings] = useState<UserSettings>({
    email: '',
    preferredMorningTime: '08:00',
    backendUrl: '',
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [briefing, setBriefing] = useState<MorningBriefing | null>(null);
  const [isGeneratingBriefing, setIsGeneratingBriefing] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  // Initial Load
  useEffect(() => {
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      const parsedSettings = JSON.parse(savedSettings);
      setSettings(parsedSettings);
      if (parsedSettings.backendUrl) {
        syncWithBackend(parsedSettings.backendUrl);
      } else {
        const savedTasks = localStorage.getItem(STORAGE_KEY);
        if (savedTasks) setTasks(JSON.parse(savedTasks));
      }
    }
  }, []);

  const syncWithBackend = async (url: string) => {
    setIsSyncing(true);
    try {
      const fetchedTasks = await apiService.getTasks(url);
      setTasks(fetchedTasks);
    } catch (error) {
      console.error("Sync failed:", error);
      // Fallback to local
      const savedTasks = localStorage.getItem(STORAGE_KEY);
      if (savedTasks) setTasks(JSON.parse(savedTasks));
    } finally {
      setIsSyncing(false);
    }
  };

  const addTask = async (taskData: Omit<Task, 'id' | 'createdAt' | 'completed'>) => {
    if (settings.backendUrl) {
      setIsSyncing(true);
      try {
        const newTask = await apiService.createTask(settings.backendUrl, taskData);
        setTasks(prev => [newTask, ...prev]);
      } catch (err) {
        alert("Failed to save to backend. Task saved locally.");
        saveLocally(taskData);
      } finally {
        setIsSyncing(false);
      }
    } else {
      saveLocally(taskData);
    }
    setIsModalOpen(false);
  };

  const saveLocally = (taskData: Omit<Task, 'id' | 'createdAt' | 'completed'>) => {
    const newTask: Task = {
      ...taskData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      completed: false
    };
    const updated = [newTask, ...tasks];
    setTasks(updated);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  };

  const toggleTask = async (id: string) => {
    if (settings.backendUrl) {
      setIsSyncing(true);
      try {
        await apiService.toggleTask(settings.backendUrl, id);
        setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
      } catch (err) {
        console.error(err);
      } finally {
        setIsSyncing(false);
      }
    } else {
      const updated = tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t);
      setTasks(updated);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
    }
  };

  const deleteTask = async (id: string) => {
    if (settings.backendUrl) {
      setIsSyncing(true);
      try {
        await apiService.deleteTask(settings.backendUrl, id);
        setTasks(prev => prev.filter(t => t.id !== id));
      } catch (err) {
        console.error(err);
      } finally {
        setIsSyncing(false);
      }
    } else {
      const updated = tasks.filter(t => t.id !== id);
      setTasks(updated);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
    }
  };

  const handleGenerateBriefing = async () => {
    setIsGeneratingBriefing(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const todaysTasks = tasks.filter(t => t.date === today && !t.completed);
      const result = await generateMorningBriefing(todaysTasks);
      setBriefing(result);
    } catch (error) {
      console.error("Briefing failed:", error);
    } finally {
      setIsGeneratingBriefing(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar */}
      <nav className="w-full md:w-72 bg-white border-b md:border-r border-slate-200 p-8 flex flex-col gap-8 sticky top-0 z-50 md:h-screen">
        <div className="flex items-center gap-3 text-orange-600">
          <Sun className="w-10 h-10 fill-current animate-pulse" />
          <h1 className="text-2xl font-serif italic font-extrabold text-slate-900 tracking-tight">MorningZen</h1>
        </div>

        <div className="flex flex-col gap-1">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center gap-3 px-5 py-3.5 rounded-2xl transition-all ${activeTab === 'dashboard' ? 'bg-orange-50 text-orange-600 font-semibold shadow-sm shadow-orange-100' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <LayoutDashboard size={20} />
            Daily Flow
          </button>
          <button 
            onClick={() => setActiveTab('calendar')}
            className={`flex items-center gap-3 px-5 py-3.5 rounded-2xl transition-all ${activeTab === 'calendar' ? 'bg-orange-50 text-orange-600 font-semibold shadow-sm shadow-orange-100' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <CalendarIcon size={20} />
            Timeline
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`flex items-center gap-3 px-5 py-3.5 rounded-2xl transition-all ${activeTab === 'settings' ? 'bg-orange-50 text-orange-600 font-semibold shadow-sm shadow-orange-100' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <SettingsIcon size={20} />
            Connection
          </button>
        </div>

        <div className="mt-auto space-y-4">
          {isSyncing && (
            <div className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-orange-400 bg-orange-50/50 p-2 rounded-lg">
              <RefreshCw size={12} className="animate-spin" />
              Syncing Cloud
            </div>
          )}
          <button 
            onClick={() => setIsModalOpen(true)}
            className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-4 rounded-2xl shadow-xl shadow-slate-200 transition-all flex items-center justify-center gap-2"
          >
            <Plus size={22} />
            New Action Item
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto p-6 md:p-12 max-w-6xl mx-auto w-full">
        {activeTab === 'dashboard' && (
          <Dashboard 
            tasks={tasks} 
            toggleTask={toggleTask} 
            deleteTask={deleteTask}
            briefing={briefing}
            onGenerateBriefing={handleGenerateBriefing}
            isGenerating={isGeneratingBriefing}
          />
        )}
        {activeTab === 'calendar' && (
          <CalendarView tasks={tasks} toggleTask={toggleTask} deleteTask={deleteTask} />
        )}
        {activeTab === 'settings' && (
          <SettingsView settings={settings} setSettings={setSettings} onSync={() => syncWithBackend(settings.backendUrl || '')} />
        )}
      </main>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] w-full max-w-lg p-8 shadow-2xl animate-in fade-in zoom-in duration-300">
            <div className="flex items-center gap-3 mb-8">
              <div className="p-3 bg-orange-100 rounded-2xl text-orange-600">
                <Sparkles size={24} />
              </div>
              <h2 className="text-2xl font-serif italic font-bold">New Daily Task</h2>
            </div>
            <TaskForm onSubmit={addTask} onCancel={() => setIsModalOpen(false)} />
          </div>
        </div>
      )}
    </div>
  );
};

