const CalendarView: React.FC<{ tasks: Task[]; toggleTask: (id: string) => void; deleteTask: (id: string) => void; }> = ({ tasks, toggleTask, deleteTask }) => {
  const [viewDate, setViewDate] = useState(new Date());
  const dateStr = (y: number, m: number, d: number) => `${y}-${String(m + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;

  const daysInMonth = new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  const firstDay = new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay();

  const nextMonth = () => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1));
  const prevMonth = () => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1));

  return (
    <div className="animate-in fade-in slide-in-from-right-8 duration-700">
      <div className="flex items-center justify-between mb-10">
        <h2 className="text-3xl font-serif italic font-bold flex items-center gap-4">
          <CalendarIcon size={32} className="text-orange-500" />
          {viewDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
        </h2>
        <div className="flex gap-3">
          <button onClick={prevMonth} className="p-3 bg-white hover:bg-slate-50 rounded-2xl border border-slate-200 shadow-sm transition-all"><ChevronLeft /></button>
          <button onClick={nextMonth} className="p-3 bg-white hover:bg-slate-50 rounded-2xl border border-slate-200 shadow-sm transition-all"><ChevronRight /></button>
        </div>
      </div>

      <div className="grid grid-cols-7 gap-px bg-slate-200 border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm mb-12">
        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
          <div key={day} className="bg-slate-50 py-5 text-center text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">{day}</div>
        ))}
        {Array.from({ length: firstDay }).map((_, i) => <div key={`empty-${i}`} className="bg-white/40"></div>)}
        {Array.from({ length: daysInMonth }).map((_, i) => {
          const d = i + 1;
          const current = dateStr(viewDate.getFullYear(), viewDate.getMonth(), d);
          const dayTasks = tasks.filter(t => t.date === current);
          const isToday = new Date().toISOString().split('T')[0] === current;

          return (
            <div key={d} className="bg-white min-h-[140px] p-3 border-t border-slate-100 flex flex-col gap-2 group hover:bg-slate-50/50 transition-colors">
              <span className={`text-sm font-bold w-7 h-7 flex items-center justify-center rounded-xl ${isToday ? 'bg-orange-500 text-white' : 'text-slate-400 group-hover:text-slate-900'}`}>{d}</span>
              <div className="flex flex-col gap-1.5 overflow-y-auto max-h-[80px] scrollbar-hide">
                {dayTasks.map(t => (
                  <div key={t.id} className={`text-[10px] font-bold px-2 py-1 rounded-lg truncate border ${t.completed ? 'bg-slate-50 text-slate-300 border-transparent' : 'bg-orange-50 text-orange-700 border-orange-100'}`}>
                    {t.title}
                  </div>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

