export default App;

import { Task, UserSettings } from "../types";

export const apiService = {
  async getTasks(baseUrl: string): Promise<Task[]> {
    const response = await fetch(`${baseUrl}/tasks`);
    if (!response.ok) throw new Error('Failed to fetch tasks');
    return response.json();
  },

  async createTask(baseUrl: string, task: Omit<Task, 'id' | 'createdAt' | 'completed'>): Promise<Task> {
    const response = await fetch(`${baseUrl}/tasks`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(task),
    });
    if (!response.ok) throw new Error('Failed to create task');
    return response.json();
  },

  async toggleTask(baseUrl: string, taskId: string): Promise<any> {
    const response = await fetch(`${baseUrl}/tasks/${taskId}/toggle`, {
      method: 'PATCH',
    });
    if (!response.ok) throw new Error('Failed to update task');
    return response.json();
  },

  async deleteTask(baseUrl: string, taskId: string): Promise<void> {
    const response = await fetch(`${baseUrl}/tasks/${taskId}`, {
      method: 'DELETE',
    });
    if (!response.ok) throw new Error('Failed to delete task');
  },

  async saveSettings(baseUrl: string, settings: UserSettings): Promise<void> {
    const response = await fetch(`${baseUrl}/settings`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        email: settings.email,
        preferredMorningTime: settings.preferredMorningTime
      }),
    });
    if (!response.ok) throw new Error('Failed to save settings');
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Calendar as CalendarIcon, 
  CheckCircle2, 
  Clock, 
  LayoutDashboard, 
  Plus, 
  Settings as SettingsIcon,
  Sun,
  Trash2,
  Mail,
  Sparkles,
  ChevronLeft,
  ChevronRight,
  RefreshCw,
  Database,
  ArrowRight
} from 'lucide-react';
import { Task, TaskPriority, MorningBriefing, UserSettings } from './types';
import { generateMorningBriefing } from './services/geminiService';
import { apiService } from './services/apiService';

const STORAGE_KEY = 'morningzen_tasks';
const SETTINGS_KEY = 'morningzen_settings';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'calendar' | 'settings'>('dashboard');
  const [tasks, setTasks] = useState<Task[]>([]);
  const [settings, setSettings] = useState<UserSettings>({
    email: '',
    preferredMorningTime: '08:00',
    backendUrl: '',
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [briefing, setBriefing] = useState<MorningBriefing | null>(null);
  const [isGeneratingBriefing, setIsGeneratingBriefing] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      const parsedSettings = JSON.parse(savedSettings);
      setSettings(parsedSettings);
      if (parsedSettings.backendUrl) {
        syncWithBackend(parsedSettings.backendUrl);
      }
    }
  }, []);

  const syncWithBackend = async (url: string) => {
    setIsSyncing(true);
    try {
      const fetchedTasks = await apiService.getTasks(url);
      setTasks(fetchedTasks);
    } catch (error) {
      console.error("Sync failed:", error);
    } finally {
      setIsSyncing(false);
    }
  };

  const addTask = async (taskData: Omit<Task, 'id' | 'createdAt' | 'completed'>) => {
    if (settings.backendUrl) {
      setIsSyncing(true);
      try {
        const newTask = await apiService.createTask(settings.backendUrl, taskData);
        setTasks(prev => [newTask, ...prev]);
      } catch (err) {
        console.error(err);
      } finally {
        setIsSyncing(false);
      }
    } else {
      const newTask: Task = {
        ...taskData,
        id: Math.random().toString(36).substr(2, 9),
        createdAt: Date.now(),
        completed: false
      };
      setTasks(prev => [newTask, ...prev]);
    }
    setIsModalOpen(false);
  };

  const toggleTask = async (id: string) => {
    if (settings.backendUrl) {
      setIsSyncing(true);
      try {
        await apiService.toggleTask(settings.backendUrl, id);
        setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
      } catch (err) {
        console.error(err);
      } finally {
        setIsSyncing(false);
      }
    } else {
      setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
    }
  };

  const deleteTask = async (id: string) => {
    if (settings.backendUrl) {
      setIsSyncing(true);
      try {
        await apiService.deleteTask(settings.backendUrl, id);
        setTasks(prev => prev.filter(t => t.id !== id));
      } catch (err) {
        console.error(err);
      } finally {
        setIsSyncing(false);
      }
    } else {
      setTasks(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleSaveSettings = async (newSettings: UserSettings) => {
    setSettings(newSettings);
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(newSettings));
    if (newSettings.backendUrl) {
      try {
        await apiService.saveSettings(newSettings.backendUrl, newSettings);
        syncWithBackend(newSettings.backendUrl);
      } catch (err) {
        console.error("Backend settings sync failed:", err);
      }
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row text-slate-900 selection:bg-orange-100">
      <nav className="w-full md:w-72 bg-white border-b md:border-r border-slate-200 p-8 flex flex-col gap-8 sticky top-0 z-50 md:h-screen">
        <div className="flex items-center gap-3">
          <div className="bg-orange-500 p-2 rounded-xl shadow-lg shadow-orange-200">
            <Sun className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-2xl font-serif italic font-extrabold tracking-tight">MorningZen</h1>
        </div>

        <div className="flex flex-col gap-1">
          <NavItem active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Daily Flow" />
          <NavItem active={activeTab === 'calendar'} onClick={() => setActiveTab('calendar')} icon={<CalendarIcon size={20}/>} label="Timeline" />
          <NavItem active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} icon={<SettingsIcon size={20}/>} label="Infrastructure" />
        </div>

        <div className="mt-auto space-y-4">
          {isSyncing && (
            <div className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-orange-500 bg-orange-50 px-3 py-2 rounded-full animate-pulse">
              <RefreshCw size={12} className="animate-spin" />
              Syncing Cloud
            </div>
          )}
          <button 
            onClick={() => setIsModalOpen(true)}
            className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-4 rounded-2xl shadow-xl shadow-slate-200 transition-all flex items-center justify-center gap-2 active:scale-[0.98]"
          >
            <Plus size={22} />
            New Intention
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto p-6 md:p-12 max-w-6xl mx-auto w-full">
        {activeTab === 'dashboard' && (
          <Dashboard 
            tasks={tasks} 
            toggleTask={toggleTask} 
            deleteTask={deleteTask}
            briefing={briefing}
            onGenerateBriefing={async () => {
              setIsGeneratingBriefing(true);
              const today = new Date().toISOString().split('T')[0];
              const t = tasks.filter(x => x.date === today && !x.completed);
              const b = await generateMorningBriefing(t);
              setBriefing(b);
              setIsGeneratingBriefing(false);
            }}
            isGenerating={isGeneratingBriefing}
          />
        )}
        {activeTab === 'calendar' && <CalendarView tasks={tasks} toggleTask={toggleTask} deleteTask={deleteTask} />}
        {activeTab === 'settings' && <SettingsView settings={settings} onSave={handleSaveSettings} />}
      </main>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-lg p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
             <h2 className="text-3xl font-serif italic font-bold mb-8">What's on your mind?</h2>
             <TaskForm onSubmit={addTask} onCancel={() => setIsModalOpen(false)} />
          </div>
        </div>
      )}
    </div>
  );
};

const NavItem = ({ active, onClick, icon, label }: any) => (
  <button 
    onClick={onClick}
    className={`flex items-center gap-3 px-5 py-4 rounded-2xl transition-all ${active ? 'bg-orange-50 text-orange-600 font-bold shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}
