  return (
    <div className="space-y-12 animate-in slide-in-from-bottom-8 duration-700">
      <header className="flex flex-col md:flex-row items-center justify-between gap-8 bg-white p-10 md:p-16 rounded-[3rem] border border-slate-200 relative overflow-hidden group">
