            <h2 className="text-5xl font-serif italic mb-4 tracking-tight">Rise and shine.</h2>
            <p className="text-slate-500 text-xl font-medium">Today, you've committed to <span className="text-orange-600 font-bold">{pending} intentions</span>.</p>
         </div>
         <button 
            disabled={isGenerating}
            onClick={onGenerateBriefing}
            className="relative z-10 bg-orange-500 hover:bg-orange-600 text-white px-10 py-5 rounded-full font-bold shadow-2xl shadow-orange-100 flex items-center gap-3 active:scale-95 transition-all disabled:opacity-50"
         >
           {isGenerating ? <RefreshCw className="animate-spin"/> : <Sparkles size={22}/>}
           {isGenerating ? "Consulting Stars..." : "Generate Briefing"}
         </button>
         <div className="absolute -right-20 -bottom-20 w-80 h-80 bg-orange-50 rounded-full blur-[120px] opacity-40 group-hover:opacity-70 transition-opacity"></div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <section className="lg:col-span-7 space-y-8">
           <h3 className="text-2xl font-serif italic font-bold flex items-center gap-3">
              Today's Agenda
