           <div className="space-y-4">
              {todayTasks.length === 0 ? (
                <div className="py-20 bg-white rounded-[2rem] border-2 border-dashed border-slate-100 flex flex-col items-center gap-4">
                  <p className="text-slate-400 italic">No plans yet. Pure possibility.</p>
                </div>
              ) : (
                todayTasks.map((t: Task) => <TaskCard key={t.id} task={t} onToggle={toggleTask} onDelete={deleteTask}/>)
