  return (
    <form className="space-y-6" onSubmit={(e) => { e.preventDefault(); onSubmit(f); }}>
      <input autoFocus required placeholder="Intention Name" className="w-full text-2xl font-serif italic border-b-2 border-slate-100 focus:border-orange-500 focus:outline-none py-2 transition-all" value={f.title} onChange={e => setF({...f, title: e.target.value})} />
      <textarea placeholder="Supporting details..." className="w-full p-4 rounded-2xl bg-slate-50 border border-transparent focus:bg-white focus:border-slate-100 focus:outline-none transition-all resize-none" rows={3} value={f.description} onChange={e => setF({...f, description: e.target.value})} />
      <div className="grid grid-cols-2 gap-6">
        <input type="date" className="p-4 rounded-2xl bg-slate-50 font-bold focus:outline-none" value={f.date} onChange={e => setF({...f, date: e.target.value})} />
        <select className="p-4 rounded-2xl bg-slate-50 font-bold focus:outline-none" value={f.priority} onChange={e => setF({...f, priority: e.target.value as TaskPriority})}>
          {Object.values(TaskPriority).map(p => <option key={p} value={p}>{p}</option>)}
        </select>
      </div>
      <div className="flex gap-4 pt-6">
        <button type="button" onClick={onCancel} className="flex-1 py-4 rounded-2xl font-bold text-slate-400 hover:text-slate-600 transition-all">Discard</button>
        <button type="submit" className="flex-1 py-4 rounded-2xl bg-slate-900 text-white font-bold hover:bg-slate-800 transition-all shadow-xl shadow-slate-200">Seal Intention</button>
      </div>
    </form>
  );
};

