import os
import datetime
from typing import List, Optional
from fastapi import FastAPI, HTTPException, Request
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from supabase import create_client, Client
import sib_api_v3_sdk
from sib_api_v3_sdk.rest import ApiException
import google.generativeai as genai

app = FastAPI()

# CORS for Vercel Frontend and local development
app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_methods=["*"],
    allow_headers=["*"],
)

# Config
SUPABASE_URL = os.environ.get("SUPABASE_URL")
SUPABASE_KEY = os.environ.get("SUPABASE_ANON_KEY")
GEMINI_KEY = os.environ.get("API_KEY")
BREVO_KEY = os.environ.get("BREVO_API_KEY")
SENDER_EMAIL = os.environ.get("SENDER_EMAIL")

# Initialize Supabase only if keys are present
supabase: Optional[Client] = None
if SUPABASE_URL and SUPABASE_KEY:
    supabase = create_client(SUPABASE_URL, SUPABASE_KEY)

# Configure Gemini
if GEMINI_KEY:
    genai.configure(api_key=GEMINI_KEY)

class Task(BaseModel):
    id: Optional[str] = None
    title: str
    description: Optional[str] = ""
    date: str
    priority: str
    completed: bool = False

# --- Core Logic ---

def send_email(to_email: str, subject: str, content: str):
    if not BREVO_KEY or not SENDER_EMAIL:
        print("Email config missing")
        return

    configuration = sib_api_v3_sdk.Configuration()
    configuration.api_key['api-key'] = BREVO_KEY
    api_instance = sib_api_v3_sdk.TransactionalEmailsApi(sib_api_v3_sdk.ApiClient(configuration))

    send_smtp_email = sib_api_v3_sdk.SendSmtpEmail(
        to=[{"email": to_email}],
        sender={"email": SENDER_EMAIL, "name": "MorningZen"},
        subject=subject,
        html_content=f"<html><body style='font-family: sans-serif; line-height: 1.6;'>{content}</body></html>"
    )
    try:
        api_instance.send_trans_email(send_smtp_email)
    except ApiException as e:
        print(f"Brevo API Exception: {e}")

def get_ai_briefing(tasks):
    if not GEMINI_KEY:
        return "Gemini API key is missing. Please check your environment variables."

    model = genai.GenerativeModel('gemini-1.5-flash')
    task_str = "\n".join([f"- {t['title']} ({t['priority']})" for t in tasks])
    prompt = f"Act as a zen life coach. It's morning. Give a unique quote and a warm greeting. Then, briefly summarize and give advice for these tasks:\n{task_str}\n\nKeep it elegant and concise."

    try:
        response = model.generate_content(prompt)
        return response.text
    except Exception as e:
        return f"Could not generate AI briefing: {str(e)}"

# --- API Routes ---
# We use /api prefix to match Vercel's rewrite expectations

@app.get("/api/tasks")
async def list_tasks():
    if not supabase:
        return []
    try:
        res = supabase.table("tasks").select("*").order("date").execute()
        return res.data
    except Exception as e:
        print(f"Supabase Error: {e}")
        return []

@app.post("/api/tasks")
async def add_task(task: Task):
    if not supabase:
        raise HTTPException(status_code=503, detail="Supabase not configured")
    try:
        data = task.dict(exclude_none=True)
        res = supabase.table("tasks").insert(data).execute()
        return res.data[0]
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

@app.patch("/api/tasks/{task_id}/toggle")
async def toggle(task_id: str):
    if not supabase:
        raise HTTPException(status_code=530, detail="Supabase not configured")
    try:
        res = supabase.table("tasks").select("completed").eq("id", task_id).execute()
        if not res.data:
            raise HTTPException(status_code=404, detail="Task not found")
        new_val = not res.data[0]['completed']
        supabase.table("tasks").update({"completed": new_val}).eq("id", task_id).execute()
        return {"status": "ok"}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

@app.delete("/api/tasks/{task_id}")
async def remove_task(task_id: str):
    if not supabase:
        raise HTTPException(status_code=503, detail="Supabase not configured")
    try:
        supabase.table("tasks").delete().eq("id", task_id).execute()
        return {"status": "deleted"}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

@app.get("/api/cron")
async def daily_cron_trigger(request: Request):
    if not supabase:
        return {"error": "Supabase not configured"}

    today = datetime.date.today().isoformat()
    target_email = SENDER_EMAIL 

    if not target_email:
        return {"error": "SENDER_EMAIL environment variable not set"}

    try:
        res = supabase.table("tasks").select("*").eq("date", today).eq("completed", False).execute()
        briefing = get_ai_briefing(res.data)
        send_email(target_email, "Good Morning: Your Zen Briefing", briefing.replace("\n", "<br>"))
        return {"status": "Briefing sent", "task_count": len(res.data)}
    except Exception as e:
        return {"error": str(e)}

@app.get("/api/health")
async def health():
    return {"status": "healthy", "supabase": supabase is not None, "gemini": GEMINI_KEY is not None}

